local http = require "resty.http"
local httpc = http.new()

local function is_private_ip(ip)
    if not ip then
        return true
    end
    
    local octets = {}
    for octet in string.gmatch(ip, "(%d+)") do
        table.insert(octets, tonumber(octet))
    end
    
    if #octets ~= 4 then
        return true
    end
    
    if octets[1] == 10 then
        return true
    end
    
    if octets[1] == 172 and octets[2] >= 16 and octets[2] <= 31 then
        return true
    end
    
    if octets[1] == 192 and octets[2] == 168 then
        return true
    end
    
    if octets[1] == 127 then
        return true
    end
    
    if octets[1] == 169 and octets[2] == 254 then
        return true
    end
    
    if octets[1] == 0 then
        return true
    end
    
    if octets[1] >= 224 then
        return true
    end
    
    return false
end

local function validate_url(url)
    if not url or url == "" then
        return false, "URL is required"
    end
    
    local scheme = string.match(url, "^(%w+)://")
    if scheme ~= "http" and scheme ~= "https" then
        return false, "Only HTTP and HTTPS schemes are allowed"
    end
    
    local host = string.match(url, "^%w+://([^:/]+)")
    if not host then
        return false, "Invalid URL format"
    end
    
    host = string.lower(host)
    
    if host == "localhost" or string.match(host, "%.local$") then
        return false, "Localhost and .local domains are not allowed"
    end
    
    if string.match(host, "^%d+%.%d+%.%d+%.%d+$") then
        if is_private_ip(host) then
            return false, "Private IP addresses are not allowed"
        end
    end
    
    local resolver = require "resty.dns.resolver"
    local r, err = resolver:new{
        nameservers = {"8.8.8.8", "8.8.4.4"},
        retrans = 2,
        timeout = 2000,
    }
    
    if not r then
        return false, "Failed to initialize DNS resolver: " .. (err or "unknown error")
    end
    
    local answers, err = r:query(host, {qtype = r.TYPE_A})
    if not answers then
        return false, "DNS resolution failed: " .. (err or "unknown error")
    end
    
    if answers.errcode then
        return false, "DNS error: " .. (answers.errstr or "unknown error")
    end
    
    for _, ans in ipairs(answers) do
        if ans.address then
            if is_private_ip(ans.address) then
                return false, "Target resolves to private IP address"
            end
        end
    end
    
    return true
end

local target_url = ngx.var.arg_url

local valid, err = validate_url(target_url)
if not valid then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say('{"error": "' .. err .. '"}')
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

httpc:set_timeout(5000)

local res, err = httpc:request_uri(target_url, {
    method = ngx.var.request_method,
    ssl_verify = true,
    keepalive_timeout = 60000,
    keepalive_pool = 10
})

if not res then
    ngx.status = ngx.HTTP_BAD_GATEWAY
    ngx.say('{"error": "Failed to fetch URL: ' .. (err or "unknown error") .. '"}')
    return ngx.exit(ngx.HTTP_BAD_GATEWAY)
end

ngx.status = res.status

for k, v in pairs(res.headers) do
    if k ~= "connection" and k ~= "transfer-encoding" then
        ngx.header[k] = v
    end
end

ngx.say(res.body)